export const EmailAttachmentRefWritableSchema = {
  type: "object",
  additionalProperties: false,
  required: ["filename", "size"],
  description:
    "Attachment metadata returned on API reads. The original content is not echoed back inline — only the metadata needed for display and audit. To download the raw attachment bytes (while content storage is enabled and within the retention window), use `GET /v1/email/messages/{message_id}/attachments/{attachment_id}`, which returns the file with its own content type and a Content-Disposition filename.\n",
  properties: {
    filename: {
      type: "string",
      minLength: 1,
      description: "Filename as shown to the recipient.",
      example: "invoice.pdf",
    },
    content_type: {
      type: "string",
      description: "Resolved MIME type at send time.",
      example: "application/pdf",
    },
    size: {
      type: "integer",
      minimum: 0,
      description: "Decoded size in bytes.",
      example: 215432,
    },
    inline: {
      type: "boolean",
      description:
        "True when the attachment was sent inline via a `content_id` reference in the HTML body, false for regular file attachments.\n",
      example: false,
    },
    content_id: {
      type: ["string", "null"],
      description:
        "The Content-ID set at send time, when the attachment was inline.",
    },
  },
} as const;

export const EmailMessageWritableSchema = {
  type: "object",
  additionalProperties: false,
  required: [
    "from",
    "to",
    "subject",
    "category",
    "track_opens",
    "track_clicks",
  ],
  properties: {
    from: {
      $ref: "#/components/schemas/EmailAddress",
      description:
        "Sender address. `name` is present when a display name was provided on the send.",
    },
    to: {
      type: "array",
      items: {
        $ref: "#/components/schemas/EmailAddress",
      },
      minItems: 1,
      maxItems: 50,
      description:
        "Primary recipients. Length is the recipient count; use the broadcasts endpoint for audience-targeted sends. Each entry's `name` is present when a display name was provided on the send.",
    },
    cc: {
      type: "array",
      items: {
        $ref: "#/components/schemas/EmailAddress",
      },
      description: "CC recipients.",
    },
    bcc: {
      type: "array",
      items: {
        $ref: "#/components/schemas/EmailAddress",
      },
      description: "BCC recipients.",
    },
    subject: {
      type: "string",
      minLength: 1,
      description: "Message subject line.",
    },
    category: {
      type: "string",
      minLength: 1,
      enum: ["marketing", "transactional"],
      description:
        "Content classification. Controls suppression policy — `marketing` blocks on all suppression reasons; `transactional` allows delivery through complaint and unsubscribe suppressions.\n",
    },
    reply_to: {
      type: ["array", "null"],
      items: {
        $ref: "#/components/schemas/EmailAddress",
      },
      maxItems: 25,
      description:
        "Reply-To addresses, if set on the send. Empty/null when no Reply-To was provided.",
    },
    tags: {
      type: "array",
      items: {
        $ref: "#/components/schemas/Tag",
      },
      description:
        "Structured `{name, value}` filter labels applied to this send. See EmailMessageSendRequest for the tags vs metadata distinction.",
    },
    metadata: {
      type: "object",
      description:
        "Arbitrary JSON metadata stored on the message object and echoed in webhook payloads. See EmailMessageSendRequest for the tags vs metadata distinction.",
      additionalProperties: true,
    },
    attachments: {
      type: "array",
      items: {
        $ref: "#/components/schemas/EmailAttachmentRefWritable",
      },
      description:
        "Attachment metadata for the send. Empty when no attachments were included. Raw content is not echoed; use the future content-retrieval endpoint when storage is enabled.",
    },
    track_opens: {
      type: "boolean",
      description: "Whether open tracking is enabled for this send.",
    },
    track_clicks: {
      type: "boolean",
      description: "Whether click tracking is enabled for this send.",
    },
  },
} as const;
